import React from 'react'
import { createPortal } from 'react-dom'
import useToastStore from './useToastStore'

function ToastRenderer() {
    function getBackground(type) {
        let color = 'grey'
        switch (type) {
            case TOAST_TYPE.SUCCESS: color = '#B5F5AE'
                break
            case TOAST_TYPE.ERROR: color = '#F78B8B'
                break
            case TOAST_TYPE.WARNING: color = '#FABB4D'
                break
        }
        return color
    }

    const toasts = useToastStore((state) => state.toasts)
    const toastRoot = document.getElementById('toast-root')
    if (!toastRoot) return null
    return createPortal(<div style={{ backgroundColor: getBackground(type) }} className='toast'>
        {toasts.map(({ id, component, priority, idx }) => <div className='toast-container' style={{ top: `${50 + idx * 10}px` }} key={id}>{component}</div >)
        }
    </div>
        , toastRoot)
}

export default ToastRenderer
